	private static readonly uint[,] HandRand = new uint[2, 8]
	{
		{ 0u, 300552822u, 783895074u, 1452168134u, 1022024420u, 1210474642u, 797945372u, 1184248952u },
		{ 0u, 1197611564u, 3552543762u, 1694631924u, 2184369472u, 2988240506u, 3229706824u, 1674556810u }
	};

	private ulong board;

	private uint hand;

	public ulong BoardKey => board;

	public uint HandKey => hand;

	public HashKey(SPosition pos)
	{
		board = 0uL;
		hand = 337908088u;
		Init(pos);
	}

	public HashKey(ulong board, uint hand)
	{
		this.board = board;
		this.hand = hand;
	}

	public HashKey(HashKey hashkey)
	{
		board = hashkey.board;
		hand = hashkey.hand;
	}

	public ulong Key()
	{
		return board ^ hand;
	}

	public override int GetHashCode()
	{
		return board.GetHashCode() ^ hand.GetHashCode();
	}

	public override bool Equals(object obj)
	{
		if (obj == null)
		{
			return false;
		}
		HashKey hashKey = (HashKey)obj;
		if (board == hashKey.board)
		{
			return hand == hashKey.hand;
		}
		return false;
	}

	public void Init(SPosition pos)
	{
		ulong num = 0uL;
		for (int i = 0; i < 81; i++)
		{
			Piece piece = pos.GetPiece(i);
			num ^= BoardRand[(uint)piece, i];
		}
		board = num;
		uint num2 = 337908088u;
		for (int j = 1; j < 8; j++)
		{
			for (int k = 0; k < pos.BlackHand[j]; k++)
			{
				num2 += HandRand[0, j];
			}
		}
		for (int l = 1; l < 8; l++)
		{
			for (int m = 0; m < pos.WhiteHand[l]; m++)
			{
				num2 += HandRand[1, l];
			}
		}
		hand = num2 | ((pos.Turn != PlayerColor.Black) ? 1u : 0u);
	}

	public void MoveHash(MoveData move_data)
	{
		Move(move_data.ToSquare, move_data.FromSquare, move_data.Piece, move_data.MoveType, move_data.CapturePiece);
	}

	public void Move(int to, int from, Piece piece, MoveType move_type, Piece capturePiece)
	{
		if (move_type != MoveType.Pass)
		{
			board ^= fromhash(from, move_type, piece);
			board ^= caphash(to, capturePiece);
			board ^= tohash(to, move_type, piece);
			hand -= drophand(move_type, piece);
			hand += caphand(piece.ColorOf(), capturePiece);
		}
		hand ^= 1u;
	}

	public void UnMoveHash(MoveData move_data)
	{
		UnMove(move_data.ToSquare, move_data.FromSquare, move_data.Piece, move_data.MoveType, move_data.CapturePiece);
	}

	public void UnMove(int to, int from, Piece piece, MoveType move_type, Piece capturePiece)
	{
		if (move_type != MoveType.Pass)
		{
			board ^= fromhash(from, move_type, piece);
			board ^= caphash(to, capturePiece);
			board ^= tohash(to, move_type, piece);
			hand += drophand(move_type, piece);
			hand -= caphand(piece.ColorOf(), capturePiece);
		}
		hand ^= 1u;
	}

	private ulong tohash(int to, MoveType move_type, Piece piece)
	{
		int num = (int)piece;
		if (move_type.HasFlag(MoveType.MoveMask))
		{
			num += 8;
		}
		return BoardRand[num, to];
	}

	private ulong fromhash(int from, MoveType move_type, Piece piece)
	{
		if (move_type.HasFlag(MoveType.MoveFlag))
		{
			return BoardRand[(uint)piece, from];
		}
		return 0uL;
	}

	private ulong caphash(int sq, Piece piece)
	{
		if (piece != Piece.NoPiece)
		{
			return BoardRand[(uint)piece, sq];
		}
		return 0uL;
	}

	private uint drophand(MoveType type, Piece piece)
	{
		uint result = 0u;
		if (type.HasFlag(MoveType.DropFlag))
		{
			result = HandRand[(int)piece.ColorOf(), piece.ToHandIndex()];
		}
		return result;
	}

	private uint caphand(PlayerColor turn, Piece cap)
	{
		int num = cap.ToHandIndex();
		if (turn == PlayerColor.White)
		{
			num += 16;
		}
		return HandRand[(int)turn, cap.ToHandIndex()];
	}
}
